mapper.update:
UPDATE bike_order
end_time = #{endTime}, end_lng = #{endLng}, end_lat = #{endLat}, duration = #{duration}, amount = #{amount}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT , b.bike_code
FROM bike_order o
LEFT JOIN bike b ON o.bike_id = b.id
WHERE o.user_id = #{userId}
AND o.status = #{status}
ORDER BY o.create_time DESC
